index 76234ccfdcff..da1826c51b5b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1862,6 +1862,7 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   if (Value *V = simplifySubInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -2029,6 +2030,36 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C0 - ((C1 - X) & Mask) --> X & (C0 | (C0 - Step))
+    // if:
+    //  * (C1 - X) is marked nuw
+    //  * Mask clears a contiguous low-bit mask, i.e. ~Mask is 2^k-1
+    //  * C0 is aligned to Step = 2^k
+    //  * C1 == C0 + (Step - 1)
+    //
+    // Example:
+    //   64 - ((71 - X) & -8) --> X & 120
+    Value *InnerX;
+    const APInt *C0, *C1, *Mask;
+    if (match(Op0, m_APInt(C0)) &&
+        match(Op1, m_And(m_OneUse(m_Sub(m_APInt(C1), m_Value(InnerX))),
+                         m_APInt(Mask)))) {
+      auto *Sub = dyn_cast<BinaryOperator>(cast<Instruction>(Op1)->getOperand(0));
+      if (Sub && Sub->getOpcode() == Instruction::Sub && Sub->hasNoUnsignedWrap() &&
+          C0->getBitWidth() == C1->getBitWidth() &&
+          C0->getBitWidth() == Mask->getBitWidth()) {
+        APInt LowMask = ~(*Mask);
+        if (LowMask.isMask()) {
+          APInt Step = LowMask + 1;
+          if (((*C0) & LowMask).isZero() && *C1 == *C0 + LowMask) {
+            APInt ResultMask = *C0 | (*C0 - Step);
+            return BinaryOperator::CreateAnd(
+                InnerX, ConstantInt::get(I.getType(), ResultMask));
+          }
+        }
+      }
+    }
   }

   const APInt *Op0C;
@@ -2301,6 +2332,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

